16	import { createCredentialsStoreDbPlugin } from '@ax/credentials-store-db';
17	import { createCredentialsAnthropicOauthPlugin } from '@ax/credentials-anthropic-oauth';
18	import { createIpcHttpPlugin } from '@ax/ipc-http';
19	import { createAgentsPlugin } from '@ax/agents';
20	import { createHttpServerPlugin } from '@ax/http-server';
21	import { createAuthPlugin, type AuthConfig } from '@ax/auth-oidc';
22	import { createTeamsPlugin } from '@ax/teams';
23	import { createStaticFilesPlugin } from '@ax/static-files';
24	
25	// ---------------------------------------------------------------------------
26	// @ax/preset-k8s — production assembly: postgres trio + workspace-git +
27	// sandbox-k8s + claude-sdk runner.
28	//
29	// Per architecture doc Section 9, a preset is a meta-package: bumping its
30	// version ships a coordinated release of "k8s mode is now this set of plugin
31	// versions." The runtime contribution is `createK8sPlugins(config)`, which
32	// returns the assembled plugin list ready for `bootstrap()`.
33	//
34	// Why this lives in a preset and not the CLI:
35	//   - The CLI assembles the LOCAL profile (sqlite + sandbox-subprocess +
36	//     session-inmemory). That set is fine for a single laptop and the canary
37	//     test, but it can't run multi-replica because session/storage/eventbus
38	//     are in-process.
39	//   - The k8s profile swaps in the postgres trio (cross-process state),
40	//     workspace-git (durable workspace versioning), and sandbox-k8s (pods
41	//     instead of subprocesses).
42	//   - The CLI is the one place permitted to import plugins directly
43	//     (eslint allowlist); presets/** is in the same allowlist for the same
44	//     reason — they exist to compose plugins.
45	//
46	// Order matters for plugin loading. The kernel tops-sorts on declared
47	// calls/registers, but pushing in a sensible order keeps the intent obvious
48	// to readers. We mirror the CLI's order for the equivalent plugins:
49	//   1. database / storage / credentials (stateful base layer)
50	//   2. eventbus / session (cross-process coordination)
51	//   3. workspace (versioned content)
52	//   4. audit-log (subscribes to chat:end; calls storage:set)
53	//   5. http-server / auth / teams (control plane access — Week 9.5)
54	//   6. sandbox / ipc-http / chat-orchestrator (chat plane)
55	//   7. tool-dispatcher → tool descriptors → mcp-client (catalog assembly)
56	//   8. agents (admin endpoints + agents:resolve gate)
57	//
58	// (Host-side LLM plugins were deleted in Phase 6 — the SDK runner reaches
59	// Anthropic via the credential-proxy, not through a host `llm:call` hook.)
60	// ---------------------------------------------------------------------------
61	
62	const requireFromPreset = createRequire(import.meta.url);
63	
64	/**
65	 * Default location of the claude-sdk runner binary. Resolved against the
66	 * preset's own URL so pnpm hoisting and prod/dev installs both work.
67	 */
68	function defaultRunnerBinary(): string {
69	  return requireFromPreset.resolve('@ax/agent-claude-sdk-runner');
70	}
71	
72	const DEFAULT_CHAT_TIMEOUT_MS = 10 * 60_000;
73	
74	const COOKIE_KEY_BYTES = 32;
75	
76	/**
77	 * Parse the http cookie signing key from the preset config's string form
78	 * (64 hex chars OR 44 base64 chars → 32 raw bytes). Mirrors the parser
79	 * inside @ax/http-server (which we can't import — Invariant I2 — even
80	 * though the preset itself is on the cross-plugin allowlist, copying the
81	 * three-line check keeps the contract here legible).
82	 */
83	function parseCookieKeyString(raw: string): Buffer {
84	  if (typeof raw !== 'string' || raw.length === 0) {
85	    throw new PluginError({
86	      code: 'invalid-cookie-key',
87	      plugin: '@ax/preset-k8s',
88	      message:
89	        'http.cookieKey is required (32 bytes; 64 hex chars or 44 base64 chars)',
90	    });
91	  }
92	  if (/^[0-9a-fA-F]{64}$/.test(raw)) {
93	    return Buffer.from(raw, 'hex');
94	  }
95	  const b64 = Buffer.from(raw, 'base64');
96	  if (b64.length === COOKIE_KEY_BYTES) return b64;
97	  throw new PluginError({
98	    code: 'invalid-cookie-key',
99	    plugin: '@ax/preset-k8s',
100	    message:
101	      'http.cookieKey must be 32 bytes (64 hex chars or 44 base64 chars)',
102	  });
103	}
