105	/**
106	 * Discriminated union for the workspace backend. `local` keeps the
107	 * single-replica on-PVC bare repo path; `http` forwards every workspace op to
108	 * the shared git-server pod so multiple host replicas can share state.
109	 */
110	export type K8sWorkspaceConfig =
111	  | { backend: 'local'; repoRoot: string }
112	  | { backend: 'http'; baseUrl: string; token: string };
113	
114	export interface K8sPresetConfig {
115	  /**
116	   * Postgres pool config used by @ax/database-postgres + @ax/storage-postgres.
117	   * (Storage doesn't take its own connection — it reaches the shared pool
118	   * via `database:get-instance`.)
119	   */
120	  database: {
121	    connectionString: string;
122	    poolMax?: number;
123	  };
124	  /**
125	   * Eventbus opens its OWN dedicated pg.Client for LISTEN/NOTIFY — pooled
126	   * connections can't hold a LISTEN binding through idle returns. So this
127	   * is intentionally a separate connectionString (typically the same DSN).
128	   */
129	  eventbus: {
130	    connectionString: string;
131	  };
132	  /**
133	   * Same deal: session-postgres opens its own pool + listen client because
134	   * inbox claim-work blocks on LISTEN. Configured separately.
135	   */
136	  session: {
137	    connectionString: string;
138	    poolMax?: number;
139	  };
140	  /**
141	   * Workspace backend selection. Two flavors:
142	   *
143	   *   - `local`: `@ax/workspace-git` writes a bare repo on the host pod's PVC.
144	   *     Single-replica deploys only — two hosts mounting the same RWO PVC
145	   *     would race. `repoRoot` is the directory hosting `<repoRoot>/repo.git`;
146	   *     the plugin idempotently `git init`s it on first use.
147	   *
148	   *   - `http`: `@ax/workspace-git-http` forwards every workspace op to the
149	   *     dedicated git-server pod over HTTP. Multi-replica capable. `baseUrl`
150	   *     points at the git-server's cluster Service; `token` is the shared
151	   *     bearer token (via Helm-managed Secret).
152	   *
153	   * The Helm chart drives this via `workspace.backend: local|http` and the
154	   * env vars `AX_WORKSPACE_BACKEND` / `AX_WORKSPACE_ROOT` /
155	   * `AX_WORKSPACE_GIT_HTTP_URL` / `AX_WORKSPACE_GIT_HTTP_TOKEN`. The host
156	   * entrypoint reads those and constructs this config.
157	   */
158	  workspace: K8sWorkspaceConfig;
159	  /**
160	   * Pod template + readiness/limits config for sandbox-k8s. All fields
161	   * optional; defaults live in @ax/sandbox-k8s/src/config.ts.
162	   */
163	  sandbox?: {
164	    namespace?: string;
165	    image?: string;
166	    runtimeClassName?: string;
167	    imagePullSecrets?: string[];
168	    cpuLimit?: string;
169	    memoryLimit?: string;
170	    cpuRequest?: string;
171	    memoryRequest?: string;
172	    activeDeadlineSeconds?: number;
173	    readinessPollMs?: number;
174	    readinessTimeoutMs?: number;
175	  };
176	  /**
177	   * IPC listener config — the host pod's @ax/ipc-http TCP listener that
178	   * runner pods connect to. `hostIpcUrl` is required (no useful default;
179	   * it depends on the chart's Service config). `host`/`port` default to
180	   * '0.0.0.0' / 8080 — the bind address inside the host pod.
181	   */
182	  ipc: {
183	    /** Host the @ax/ipc-http listener binds to. Default '0.0.0.0'. */
184	    host?: string;
185	    /** Port the @ax/ipc-http listener binds to. Default 8080. */
186	    port?: number;
187	    /**
188	     * Cluster-internal URL the runner pods use to reach the host's IPC
189	     * listener (e.g. `http://ax-next-host.ax-next.svc.cluster.local:80`).
190	     * Required — there is no useful default; the right value comes from
191	     * the chart's Service config (Task 12 wires the env-read).
192	     */
193	    hostIpcUrl: string;
194	  };
195	  /**
196	   * Chat orchestrator overrides. `runnerBinary` defaults to the resolved
197	   * @ax/agent-claude-sdk-runner; tests/embedders may override it.
198	   */
199	  chat?: {
200	    runnerBinary?: string;
201	    chatTimeoutMs?: number;
202	    oneShot?: boolean;
203	  };
204	  /**
205	   * @ax/http-server config. The host listener that serves /admin/*, /auth/*,
206	   * /admin/me, /admin/sign-out, and (Week 10-12) the admin UI. Distinct from
207	   * the @ax/ipc-http listener above — that one is the runner-pod ↔ host
208	   * back-channel and never faces public traffic.
209	   *
210	   * `cookieKey` accepts either 64 hex chars or 44 base64 chars (32-byte key).
211	   * It's parsed by the preset and handed to the plugin as a Buffer. We
212	   * deliberately keep the string form on the preset config so the type is
213	   * JSON-serializable for the chart's ConfigMap path.
214	   *
215	   * `allowedOrigins` is the exact-match CSRF allow-list for state-changing
216	   * methods. The admin UI's origin (Week 10-12) lands here; for now the
217	   * chart provides whatever the operator sets via env.
218	   */
219	  http: {
220	    /** Bind address. Default '0.0.0.0' for in-cluster; '127.0.0.1' for tests. */
221	    host: string;
222	    /** Bind port. Pass 0 for OS-assigned (tests). */
223	    port: number;
224	    /** 32-byte signing key as 64 hex chars or 44 base64 chars. */
225	    cookieKey: string;
226	    /** Exact-match CSRF allow-list. Empty allows only X-Requested-With callers. */
227	    allowedOrigins: string[];
228	  };
229	  /**
230	   * @ax/auth config. At least one of `google` (OIDC) or `devBootstrap`
231	   * MUST be set; the plugin throws `no-auth-providers` otherwise.
232	   *
233	   * Production deploys typically set `google` only. Dev / canary / kind
234	   * deploys set `devBootstrap` only. Both can coexist for staging-like
235	   * environments — the auth plugin won't refuse it.
236	   */
237	  auth: {
238	    google?: {
239	      clientId: string;
240	      clientSecret: string;
241	      issuer: string;
242	      redirectUri: string;
243	    };
244	    /**
245	     * If present, mints a single shared `is_admin` user from the pre-shared
246	     * token via `POST /auth/dev-bootstrap`. Refused outright when
247	     * `NODE_ENV=production` (the auth plugin throws at init).
248	     */
249	    devBootstrap?: { token: string };
250	    /** Session cookie lifetime. Default 7 days (in @ax/auth). */
251	    sessionLifetimeSeconds?: number;
252	  };
253	  /**
254	   * Phase 2 — credential-proxy socket override. Defaults to
255	   * `/var/run/ax/proxy.sock` (matches the helm chart's emptyDir mount
256	   * point on host pods). Tests pass a per-test tmpdir so unprivileged
257	   * users can bind. Production deploys leave this unset.
258	   *
259	   * `caDir` overrides where the MITM CA private key + cert PEM live;
260	   * defaults to `~/.ax/proxy-ca` inside the credential-proxy plugin.
261	   * Tests override to keep cruft out of the user's home; production
262	   * leaves this unset (or sets a chart-mounted persistent path).
263	   */
264	  credentialProxy?: {
265	    socketPath?: string;
266	    caDir?: string;
267	  };
268	  /**
269	   * Optional static-file serving (production single-binary mode). When
270	   * set, mounts `@ax/static-files` after the API routes so it serves
271	   * channel-web's bundle on otherwise-unmatched paths. SPA fallback
272	   * defaults to `true` (returns `index.html` for unknown paths so
273	   * client-side routing works). Leave unset for dev — Vite handles
274	   * static + proxy in dev.
275	   */
276	  staticFiles?: {
277	    /** Absolute path to the directory to serve (e.g., channel-web/dist). */
278	    dir: string;
279	    /** URL pattern, defaults to `/*`. */
280	    mountPath?: string;
281	    /**
282	     * SPA fallback (default `true` = serve `index.html` on miss).
283	     * Pass a string to use a different fallback file; pass `false`
284	     * to return 404 on miss.
285	     */
286	    spaFallback?: boolean | string;
287	  };
288	}
