290	/**
291	 * Build the production plugin list for k8s mode. Pass the result straight to
292	 * `bootstrap({ bus, plugins, config: {} })` from @ax/core.
293	 *
294	 * Note: the runner binary resolution relies on runtime environment (the
295	 * lookup walks node_modules). That's intentional — resolved paths are not
296	 * in the JSON config schema. Anthropic credentials live in the credentials
297	 * store (admin-seeded via /admin/credentials, Phase 9.5) and are resolved
298	 * by the credential-proxy at proxy:open-session time, not at plugin init.
299	 */
300	export function createK8sPlugins(config: K8sPresetConfig): Plugin[] {
301	  const plugins: Plugin[] = [];
302	
303	  // ----- 1. stateful base layer ------------------------------------------
304	  // database-postgres owns the shared pg.Pool. storage-postgres reaches it
305	  // via `database:get-instance` (not a direct import — invariant I2).
306	  plugins.push(
307	    createDatabasePostgresPlugin({
308	      connectionString: config.database.connectionString,
309	      ...(config.database.poolMax !== undefined
310	        ? { poolMax: config.database.poolMax }
311	        : {}),
312	    }),
313	  );
314	  plugins.push(createStoragePostgresPlugin());
315	
316	  // Credentials: facade over the storage-blob seam. The default backend
317	  // (@ax/credentials-store-db) wraps storage:get/storage:set with the
318	  // `credential:` key prefix; the facade owns AES-256-GCM and the
319	  // consumer-facing credentials:get/set/delete contract. Init throws if
320	  // AX_CREDENTIALS_KEY isn't in env.
321	  plugins.push(createCredentialsStoreDbPlugin());
322	  plugins.push(createCredentialsPlugin());
323	
324	  // Phase 3 — Anthropic OAuth per-kind sub-services. Same load reasoning
325	  // as the CLI preset: purely additive, only dispatches when an agent
326	  // actually carries a kind: 'anthropic-oauth' credential. Web-chat OAuth
327	  // routes (Phase 10–12) will register HTTP handlers from this plugin.
328	  plugins.push(createCredentialsAnthropicOauthPlugin());
329	
330	  // Phase 2 — credential-proxy on a Unix socket. The host pod mounts an
331	  // emptyDir at /var/run/ax (helm template); the proxy listens on
332	  // <mount>/proxy.sock. Sandbox pods get the SAME emptyDir mounted via
333	  // the pod template, so they can dial the socket directly. The runner-
334	  // side @ax/credential-proxy-bridge converts that to a loopback TCP
335	  // port inside the sandbox before HTTP(S)_PROXY-aware libraries reach
336	  // it. (Off-the-shelf libraries can't dial a Unix socket directly.)
337	  //
338	  // Real Anthropic credentials are seeded by the admin via the standard
339	  // credentials store (POST /admin/credentials, Phase 9.5); the proxy
340	  // resolves them at proxy:open-session time and substitutes the
341	  // ax-cred:<hex> placeholder into outbound headers mid-flight.
342	  const credentialProxyCfg: Parameters<typeof createCredentialProxyPlugin>[0] = {
343	    listen: {
344	      kind: 'unix',
345	      path: config.credentialProxy?.socketPath ?? '/var/run/ax/proxy.sock',
346	    },
347	  };
348	  if (config.credentialProxy?.caDir !== undefined) {
349	    credentialProxyCfg.caDir = config.credentialProxy.caDir;
350	  }
351	  plugins.push(createCredentialProxyPlugin(credentialProxyCfg));
352	
353	  // ----- 2. cross-process coordination ----------------------------------
354	  // Eventbus and session each own a dedicated LISTEN client.
355	  plugins.push(
356	    createEventbusPostgresPlugin({
357	      connectionString: config.eventbus.connectionString,
358	    }),
359	  );
360	  plugins.push(
361	    createSessionPostgresPlugin({
362	      connectionString: config.session.connectionString,
363	      ...(config.session.poolMax !== undefined
364	        ? { poolMax: config.session.poolMax }
365	        : {}),
366	    }),
367	  );
368	
369	  // ----- 3. workspace ----------------------------------------------------
370	  // Discriminated on `backend`. The shape difference is intentional: `local`
371	  // wants a filesystem path, `http` wants a URL + bearer token. Both register
372	  // the same four `workspace:*` service hooks (Invariant I1 — the contract is
373	  // the same regardless of backend).
374	  if (config.workspace.backend === 'http') {
375	    plugins.push(
376	      createWorkspaceGitHttpPlugin({
377	        baseUrl: config.workspace.baseUrl,
378	        token: config.workspace.token,
379	      }),
380	    );
381	  } else {
382	    plugins.push(
383	      createWorkspaceGitPlugin({
384	        repoRoot: config.workspace.repoRoot,
385	      }),
386	    );
387	  }
388	
389	  // ----- 4. audit log ----------------------------------------------------
390	  // Subscribes to chat:end and writes a record via storage:set. Pushed
391	  // before the chat-orchestrator so its subscription is in place when the
392	  // first chat:end fires.
393	  plugins.push(auditLogPlugin());
394	
395	  // ----- 5. control-plane access (Week 9.5) -----------------------------
396	  // http-server provides the public-facing listener. auth registers the
397	  // /auth/* + /admin/{me,sign-out} routes and the auth:require-user gate
398	  // every admin endpoint depends on. teams owns /admin/teams* and the
399	  // teams:* hooks the agents-plugin's team-visibility ACL calls.
400	  //
401	  // Boot order: the kernel topologically sorts on `manifest.calls`
402	  // (http:register-route → @ax/http-server, auth:require-user → @ax/auth),
403	  // so even if we shuffled the array the kernel would init http-server
404	  // before auth before agents/teams. We push in the conceptual order to
405	  // keep the intent legible to readers.
406	  plugins.push(
407	    createHttpServerPlugin({
408	      host: config.http.host,
409	      port: config.http.port,
410	      cookieKey: parseCookieKeyString(config.http.cookieKey),
411	      allowedOrigins: config.http.allowedOrigins,
412	    }),
413	  );
414	
415	  const authConfig: AuthConfig = { providers: {} };
416	  if (config.auth.google !== undefined) {
417	    authConfig.providers.google = {
418	      clientId: config.auth.google.clientId,
419	      clientSecret: config.auth.google.clientSecret,
420	      issuer: config.auth.google.issuer,
421	      redirectUri: config.auth.google.redirectUri,
422	    };
423	  }
424	  if (config.auth.devBootstrap !== undefined) {
425	    authConfig.devBootstrap = { token: config.auth.devBootstrap.token };
426	  }
427	  if (config.auth.sessionLifetimeSeconds !== undefined) {
428	    authConfig.sessionLifetimeSeconds = config.auth.sessionLifetimeSeconds;
429	  }
430	  plugins.push(createAuthPlugin(authConfig));
431	
432	  // teams: mountAdminRoutes:true so /admin/teams* lands alongside the rest
433	  // of the admin surface. The plugin's manifest expands `calls` to include
434	  // http:register-route + auth:require-user when this flag is set, which
435	  // is exactly what the kernel's topo-sort needs to see.
436	  plugins.push(createTeamsPlugin({ mountAdminRoutes: true }));
437	
438	  // static-files (optional): serves channel-web's bundle from the same
439	  // listener so cookies and CSRF stay same-origin in production. The
440	  // plugin registers a `/*` catchall LAST so every API route registered
441	  // earlier wins. When `staticFiles` is unset, no catchall is mounted
442	  // and unknown paths return 404 — the dev workflow uses Vite's proxy
443	  // instead. SPA fallback defaults on so client-side routing works.
444	  if (config.staticFiles !== undefined) {
445	    plugins.push(
446	      createStaticFilesPlugin({
447	        dir: config.staticFiles.dir,
448	        ...(config.staticFiles.mountPath !== undefined
449	          ? { mountPath: config.staticFiles.mountPath }
450	          : {}),
451	        spaFallback: config.staticFiles.spaFallback ?? true,
452	      }),
453	    );
454	  }
455	
456	  // ----- 6. chat plane ---------------------------------------------------
457	  // sandbox-k8s registers `sandbox:open-session`. No subprocess fallback
458	  // here — this preset is k8s-only.
459	  const sandboxOpts = {
460	    hostIpcUrl: config.ipc.hostIpcUrl,
461	    ...(config.sandbox?.namespace !== undefined
462	      ? { namespace: config.sandbox.namespace }
463	      : {}),
464	    ...(config.sandbox?.image !== undefined
465	      ? { image: config.sandbox.image }
466	      : {}),
467	    ...(config.sandbox?.runtimeClassName !== undefined
468	      ? { runtimeClassName: config.sandbox.runtimeClassName }
469	      : {}),
470	    ...(config.sandbox?.imagePullSecrets !== undefined
471	      ? { imagePullSecrets: config.sandbox.imagePullSecrets }
472	      : {}),
473	    ...(config.sandbox?.cpuLimit !== undefined
474	      ? { cpuLimit: config.sandbox.cpuLimit }
475	      : {}),
476	    ...(config.sandbox?.memoryLimit !== undefined
477	      ? { memoryLimit: config.sandbox.memoryLimit }
478	      : {}),
479	    ...(config.sandbox?.cpuRequest !== undefined
480	      ? { cpuRequest: config.sandbox.cpuRequest }
481	      : {}),
482	    ...(config.sandbox?.memoryRequest !== undefined
483	      ? { memoryRequest: config.sandbox.memoryRequest }
484	      : {}),
485	    ...(config.sandbox?.activeDeadlineSeconds !== undefined
486	      ? { activeDeadlineSeconds: config.sandbox.activeDeadlineSeconds }
487	      : {}),
488	    ...(config.sandbox?.readinessPollMs !== undefined
489	      ? { readinessPollMs: config.sandbox.readinessPollMs }
490	      : {}),
491	    ...(config.sandbox?.readinessTimeoutMs !== undefined
492	      ? { readinessTimeoutMs: config.sandbox.readinessTimeoutMs }
493	      : {}),
494	  };
495	  plugins.push(createSandboxK8sPlugin(sandboxOpts));
496	
497	  plugins.push(
498	    createIpcHttpPlugin({
499	      host: config.ipc.host ?? '0.0.0.0',
500	      port: config.ipc.port ?? 8080,
501	    }),
502	  );
503	
504	  const orchestratorCfg: Parameters<typeof createChatOrchestratorPlugin>[0] = {
505	    runnerBinary: config.chat?.runnerBinary ?? defaultRunnerBinary(),
506	    chatTimeoutMs: config.chat?.chatTimeoutMs ?? DEFAULT_CHAT_TIMEOUT_MS,
507	  };
508	  if (config.chat?.oneShot !== undefined) {
509	    orchestratorCfg.oneShot = config.chat.oneShot;
510	  }
511	  plugins.push(createChatOrchestratorPlugin(orchestratorCfg));
512	
513	  // ----- 7. tool catalog -------------------------------------------------
514	  // Dispatcher first — it registers `tool:register` / `tool:list`. The tool
515	  // surface is populated entirely by MCP-registered host tools today;
516	  // built-in bash/file-io descriptors are gone (Phase 6 Task 6 removed their
517	  // host-side packages — the SDK runner's sandboxed Bash/Read/Write replace
518	  // them).
519	  //
520	  // mcp-client gets `mountAdminRoutes: true` so /admin/mcp-servers* lands
521	  // alongside the rest of the admin surface. The flag expands the plugin's
522	  // manifest `calls` to include http:register-route + auth:require-user;
523	  // the kernel's topo-sort picks up the new edges automatically.
524	  plugins.push(createToolDispatcherPlugin());
525	  plugins.push(createMcpClientPlugin({ mountAdminRoutes: true }));
526	
527	  // ----- 8. agents -------------------------------------------------------
528	  // Registers `agents:resolve` (the ACL gate the chat-orchestrator hard-
529	  // depends on as of Week 9.5) AND mounts /admin/agents* routes. The
530	  // plugin's manifest `calls` already declares http:register-route +
531	  // auth:require-user as hard deps — the kernel's topo-sort blocks init
532	  // until both upstream plugins have registered. Reuses the shared
533	  // postgres pool via `database:get-instance` (no second pool).
534	  plugins.push(createAgentsPlugin());
535	
536	  return plugins;
537	}
