539	// ---------------------------------------------------------------------------
540	// Env → workspace-config helper.
541	//
542	// The Helm chart writes these env vars onto the host pod (see
543	// deploy/charts/ax-next/templates/host/deployment.yaml). The host entrypoint
544	// reads them via this helper to build the discriminated `workspace` config
545	// before calling `createK8sPlugins`.
546	//
547	//   AX_WORKSPACE_BACKEND        local | http   (default: local)
548	//   AX_WORKSPACE_ROOT           required when backend === 'local'
549	//   AX_WORKSPACE_GIT_HTTP_URL   required when backend === 'http'
550	//   AX_WORKSPACE_GIT_HTTP_TOKEN required when backend === 'http'
551	//
552	// We throw loudly on missing/unknown values rather than silently defaulting
553	// — a misconfigured workspace backend is a deploy-time bug, not a runtime
554	// surprise we want to paper over.
555	// ---------------------------------------------------------------------------
556	
557	/**
558	 * Read the `AX_WORKSPACE_*` env vars and return a `K8sWorkspaceConfig`.
559	 *
560	 * Defaults to `local` when `AX_WORKSPACE_BACKEND` is unset (matches the
561	 * chart's default). Throws when the chosen backend's required vars are
562	 * missing or when the backend value is unknown.
563	 *
564	 * @param env - the env map to read from. Defaults to `process.env`. Pass an
565	 *   explicit object to keep tests deterministic (don't rely on the real
566	 *   `process.env` leaking between cases).
567	 */
568	export function workspaceConfigFromEnv(
569	  env: NodeJS.ProcessEnv = process.env,
570	): K8sWorkspaceConfig {
571	  // Treat empty string as unset. Helm templates frequently render
572	  // `value: "{{ .Values.workspace.backend }}"` with an empty value when
573	  // the user hasn't overridden it; we want that case to default to local
574	  // rather than fall through to the unknown-backend branch.
575	  const rawBackend = env.AX_WORKSPACE_BACKEND;
576	  const backend = rawBackend === undefined || rawBackend === '' ? 'local' : rawBackend;
577	
578	  if (backend === 'local') {
579	    const repoRoot = env.AX_WORKSPACE_ROOT;
580	    if (repoRoot === undefined || repoRoot === '') {
581	      throw new Error(
582	        'AX_WORKSPACE_BACKEND=local requires AX_WORKSPACE_ROOT to be set',
583	      );
584	    }
585	    return { backend: 'local', repoRoot };
586	  }
587	
588	  if (backend === 'http') {
589	    const baseUrl = env.AX_WORKSPACE_GIT_HTTP_URL;
590	    const token = env.AX_WORKSPACE_GIT_HTTP_TOKEN;
591	    if (baseUrl === undefined || baseUrl === '') {
592	      throw new Error(
593	        'AX_WORKSPACE_BACKEND=http requires AX_WORKSPACE_GIT_HTTP_URL to be set',
594	      );
595	    }
596	    if (token === undefined || token === '') {
597	      throw new Error(
598	        'AX_WORKSPACE_BACKEND=http requires AX_WORKSPACE_GIT_HTTP_TOKEN to be set',
599	      );
600	    }
601	    return { backend: 'http', baseUrl, token };
602	  }
603	
604	  throw new Error(
605	    `unknown AX_WORKSPACE_BACKEND=${backend}; expected 'local' or 'http'`,
606	  );
607	}
608	
609	// ---------------------------------------------------------------------------
610	// Full env loader. Builds a `K8sPresetConfig` from the env vars the Helm chart
611	// stamps onto the host pod. Mirrors `workspaceConfigFromEnv`'s posture: throw
612	// loudly on missing required values rather than silently default.
613	//
614	// Required env (per the chart):
615	//   - DATABASE_URL                — postgres DSN (database/eventbus/session)
616	//   - AX_K8S_HOST_IPC_URL          — cluster URL runners use to reach @ax/ipc-http
617	//   - AX_WORKSPACE_BACKEND + the per-backend vars (delegated to workspaceConfigFromEnv)
618	//   - AX_HTTP_HOST / AX_HTTP_PORT  — public-facing http listener
619	//   - AX_HTTP_COOKIE_KEY           — 32-byte signing key (hex / base64)
620	//   - AX_HTTP_ALLOWED_ORIGINS      — CSRF allow-list (comma-separated)
621	//   - At least one of:
622	//       AX_AUTH_GOOGLE_{CLIENT_ID,CLIENT_SECRET,REDIRECT_URI,ISSUER}
623	//       AX_DEV_BOOTSTRAP_TOKEN
624	//
625	// Optional env:
626	//   - K8S_NAMESPACE / K8S_POD_IMAGE / K8S_RUNTIME_CLASS / K8S_IMAGE_PULL_SECRETS
627	//                                  — sandbox-k8s overrides
628	//   - BIND_HOST / PORT             — @ax/ipc-http listen address (defaults
629	//                                    '0.0.0.0' / 8080)
630	//   - AX_RUNNER_BINARY             — chat orchestrator override (tests)
631	//   - AX_CHAT_TIMEOUT_MS           — chat orchestrator override
632	//   - AX_AUTH_SESSION_LIFETIME_SECONDS — auth session cookie lifetime
633	//
634	// `AX_CREDENTIALS_KEY` is read by @ax/credentials at init() time — it
635	// doesn't appear in K8sPresetConfig.
636	// ---------------------------------------------------------------------------
637	
638	/**
639	 * Build a full `K8sPresetConfig` from the env vars the Helm chart sets on the
640	 * host pod. Throws on missing required values.
641	 *
642	 * @param env - the env map to read from. Defaults to `process.env`. Pass an
643	 *   explicit object to keep tests deterministic.
644	 */
645	export function loadK8sConfigFromEnv(
646	  env: NodeJS.ProcessEnv = process.env,
647	): K8sPresetConfig {
648	  const databaseUrl = env.DATABASE_URL;
649	  if (databaseUrl === undefined || databaseUrl === '') {
650	    throw new Error('DATABASE_URL is required');
651	  }
652	  const hostIpcUrl = env.AX_K8S_HOST_IPC_URL;
653	  if (hostIpcUrl === undefined || hostIpcUrl === '') {
654	    throw new Error('AX_K8S_HOST_IPC_URL is required');
655	  }
656	
657	  const sandbox: NonNullable<K8sPresetConfig['sandbox']> = {};
658	  if (env.K8S_NAMESPACE !== undefined && env.K8S_NAMESPACE !== '') {
659	    sandbox.namespace = env.K8S_NAMESPACE;
660	  }
661	  if (env.K8S_POD_IMAGE !== undefined && env.K8S_POD_IMAGE !== '') {
662	    sandbox.image = env.K8S_POD_IMAGE;
663	  }
664	  if (env.K8S_RUNTIME_CLASS !== undefined && env.K8S_RUNTIME_CLASS !== '') {
665	    sandbox.runtimeClassName = env.K8S_RUNTIME_CLASS;
666	  }
667	  if (env.K8S_IMAGE_PULL_SECRETS !== undefined && env.K8S_IMAGE_PULL_SECRETS !== '') {
668	    sandbox.imagePullSecrets = env.K8S_IMAGE_PULL_SECRETS.split(',').map((s) => s.trim()).filter((s) => s.length > 0);
669	  }
670	
671	  const ipc: K8sPresetConfig['ipc'] = { hostIpcUrl };
672	  if (env.BIND_HOST !== undefined && env.BIND_HOST !== '') {
673	    ipc.host = env.BIND_HOST;
674	  }
675	  if (env.PORT !== undefined && env.PORT !== '') {
676	    const portNum = Number(env.PORT);
677	    if (!Number.isFinite(portNum) || portNum <= 0 || portNum > 65535) {
678	      throw new Error(`invalid PORT=${env.PORT}; expected a positive integer`);
679	    }
680	    ipc.port = portNum;
681	  }
682	
683	  const chat: NonNullable<K8sPresetConfig['chat']> = {};
684	  if (env.AX_RUNNER_BINARY !== undefined && env.AX_RUNNER_BINARY !== '') {
685	    chat.runnerBinary = env.AX_RUNNER_BINARY;
686	  }
687	  if (env.AX_CHAT_TIMEOUT_MS !== undefined && env.AX_CHAT_TIMEOUT_MS !== '') {
688	    const n = Number(env.AX_CHAT_TIMEOUT_MS);
689	    if (!Number.isFinite(n) || n <= 0) {
690	      throw new Error(`invalid AX_CHAT_TIMEOUT_MS=${env.AX_CHAT_TIMEOUT_MS}; expected a positive integer`);
691	    }
692	    chat.chatTimeoutMs = n;
693	  }
694	
695	  // ---- http listener (public-facing /admin + /auth surface) -----------
696	  const httpHost = env.AX_HTTP_HOST;
697	  if (httpHost === undefined || httpHost === '') {
698	    throw new Error('AX_HTTP_HOST is required');
699	  }
700	  const httpPortRaw = env.AX_HTTP_PORT;
701	  if (httpPortRaw === undefined || httpPortRaw === '') {
702	    throw new Error('AX_HTTP_PORT is required');
703	  }
704	  const httpPort = Number(httpPortRaw);
705	  // Allow 0 (OS-assigned) — tests rely on it. Reject negatives, non-finite,
706	  // and >65535. (The k8s chart never sets 0; the ax-next test suite does.)
707	  if (!Number.isFinite(httpPort) || !Number.isInteger(httpPort) || httpPort < 0 || httpPort > 65535) {
708	    throw new Error(`invalid AX_HTTP_PORT=${httpPortRaw}; expected 0..65535`);
709	  }
710	  const cookieKey = env.AX_HTTP_COOKIE_KEY;
711	  if (cookieKey === undefined || cookieKey === '') {
712	    throw new Error('AX_HTTP_COOKIE_KEY is required (32 bytes; 64 hex chars or 44 base64 chars)');
713	  }
714	  const allowedOriginsRaw = env.AX_HTTP_ALLOWED_ORIGINS;
715	  // Treat unset OR empty as "no allow-list" — http-server then prints its
716	  // loud warn unless AX_HTTP_ALLOW_NO_ORIGINS=1 silences it. We don't try
717	  // to be opinionated here; the chart is where the operator-visible warning
718	  // really belongs.
719	  const allowedOrigins =
720	    allowedOriginsRaw === undefined || allowedOriginsRaw === ''
721	      ? []
722	      : allowedOriginsRaw
723	          .split(',')
724	          .map((s) => s.trim())
725	          .filter((s) => s.length > 0);
726	
727	  // ---- auth providers --------------------------------------------------
728	  // At least one of `google` or `devBootstrap` must be present; the auth
729	  // plugin throws `no-auth-providers` at init otherwise. We re-validate
730	  // here so the operator gets a startup error pointing at the env vars
731	  // they actually set, not at the auth plugin's internal config name.
732	  const auth: K8sPresetConfig['auth'] = {};
733	  const gClientId = env.AX_AUTH_GOOGLE_CLIENT_ID;
734	  const gClientSecret = env.AX_AUTH_GOOGLE_CLIENT_SECRET;
735	  const gRedirectUri = env.AX_AUTH_GOOGLE_REDIRECT_URI;
736	  const gIssuer = env.AX_AUTH_GOOGLE_ISSUER;
737	  const anyGoogle =
738	    (gClientId !== undefined && gClientId !== '') ||
739	    (gClientSecret !== undefined && gClientSecret !== '') ||
740	    (gRedirectUri !== undefined && gRedirectUri !== '') ||
741	    (gIssuer !== undefined && gIssuer !== '');
742	  if (anyGoogle) {
743	    // Partial google config is a deploy-time bug; fail loudly. The auth
744	    // plugin would also catch this (Issuer.discover throws on a bogus
745	    // issuer URL), but a clear startup error beats a network-shaped
746	    // failure deep inside init.
747	    if (gClientId === undefined || gClientId === '') {
748	      throw new Error('AX_AUTH_GOOGLE_CLIENT_ID is required when any AX_AUTH_GOOGLE_* var is set');
749	    }
750	    if (gClientSecret === undefined || gClientSecret === '') {
751	      throw new Error('AX_AUTH_GOOGLE_CLIENT_SECRET is required when any AX_AUTH_GOOGLE_* var is set');
752	    }
753	    if (gRedirectUri === undefined || gRedirectUri === '') {
754	      throw new Error('AX_AUTH_GOOGLE_REDIRECT_URI is required when any AX_AUTH_GOOGLE_* var is set');
755	    }
756	    if (gIssuer === undefined || gIssuer === '') {
757	      throw new Error('AX_AUTH_GOOGLE_ISSUER is required when any AX_AUTH_GOOGLE_* var is set');
758	    }
759	    auth.google = {
760	      clientId: gClientId,
761	      clientSecret: gClientSecret,
762	      redirectUri: gRedirectUri,
763	      issuer: gIssuer,
764	    };
765	  }
766	  const devToken = env.AX_DEV_BOOTSTRAP_TOKEN;
767	  if (devToken !== undefined && devToken !== '') {
768	    auth.devBootstrap = { token: devToken };
769	  }
770	  if (auth.google === undefined && auth.devBootstrap === undefined) {
771	    throw new Error(
772	      'auth requires at least one of AX_AUTH_GOOGLE_* (clientId/clientSecret/redirectUri/issuer) or AX_DEV_BOOTSTRAP_TOKEN',
773	    );
774	  }
775	  if (env.AX_AUTH_SESSION_LIFETIME_SECONDS !== undefined && env.AX_AUTH_SESSION_LIFETIME_SECONDS !== '') {
776	    const n = Number(env.AX_AUTH_SESSION_LIFETIME_SECONDS);
777	    if (!Number.isFinite(n) || !Number.isInteger(n) || n <= 0) {
778	      throw new Error(`invalid AX_AUTH_SESSION_LIFETIME_SECONDS=${env.AX_AUTH_SESSION_LIFETIME_SECONDS}; expected a positive integer`);
779	    }
780	    auth.sessionLifetimeSeconds = n;
781	  }
782	
783	  const config: K8sPresetConfig = {
784	    database: { connectionString: databaseUrl },
785	    eventbus: { connectionString: databaseUrl },
786	    session: { connectionString: databaseUrl },
787	    workspace: workspaceConfigFromEnv(env),
788	    ipc,
789	    http: {
790	      host: httpHost,
791	      port: httpPort,
792	      cookieKey,
793	      allowedOrigins,
794	    },
795	    auth,
796	  };
797	  if (Object.keys(sandbox).length > 0) config.sandbox = sandbox;
798	  if (Object.keys(chat).length > 0) config.chat = chat;
799	  if (env.AX_PROXY_SOCKET_PATH !== undefined && env.AX_PROXY_SOCKET_PATH !== '') {
800	    config.credentialProxy = { socketPath: env.AX_PROXY_SOCKET_PATH };
801	  }
802	  return config;
803	}
