input.command:
pnpm test 2>&1 | grep -E "Test Files|^.*Tests" | awk '
/Test Files/ {
  for (i=1; i<=NF; i++) {
    if ($i == "passed") tf_passed += $(i-1)
    if ($i == "skipped") tf_skipped += $(i-1)
    if ($i == "failed") tf_failed += $(i-1)
  }
}
/^.*Tests/ && !/Test Files/ {
  for (i=1; i<=NF; i++) {
    if ($i == "passed") t_passed += $(i-1)
    if ($i == "skipped") t_skipped += $(i-1)
    if ($i == "failed") t_failed += $(i-1)
  }
}
END {
  printf "Test Files: %d passed, %d skipped, %d failed\n", tf_passed, tf_skipped, tf_failed
  printf "Tests: %d passed, %d skipped, %d failed\n", t_passed, t_skipped, t_failed
}
'

