+import { describe, it, expect, beforeEach, afterEach } from 'vitest';
+import { resolveRunnerBinary } from '../main.js';
+
+describe('resolveRunnerBinary', () => {
+  let savedEnv: string | undefined;
+
+  beforeEach(() => {
+    savedEnv = process.env.AX_TEST_RUNNER_BINARY_OVERRIDE;
+    delete process.env.AX_TEST_RUNNER_BINARY_OVERRIDE;
+  });
+
+  afterEach(() => {
+    if (savedEnv === undefined) delete process.env.AX_TEST_RUNNER_BINARY_OVERRIDE;
+    else process.env.AX_TEST_RUNNER_BINARY_OVERRIDE = savedEnv;
+  });
+
+  it('uses opts.runnerBinaryOverride when set', () => {
+    expect(resolveRunnerBinary({ runnerBinaryOverride: '/tmp/fake-runner.js' })).toBe(
+      '/tmp/fake-runner.js',
+    );
+  });
+
+  it('falls back to AX_TEST_RUNNER_BINARY_OVERRIDE env var when opts override is absent', () => {
+    process.env.AX_TEST_RUNNER_BINARY_OVERRIDE = '/tmp/env-runner.js';
+    expect(resolveRunnerBinary({})).toBe('/tmp/env-runner.js');
+  });
+
+  it('opts.runnerBinaryOverride takes precedence over env var', () => {
+    process.env.AX_TEST_RUNNER_BINARY_OVERRIDE = '/tmp/env-runner.js';
+    expect(resolveRunnerBinary({ runnerBinaryOverride: '/tmp/opts-runner.js' })).toBe(
+      '/tmp/opts-runner.js',
+    );
+  });
+
+  it('defaults to resolved @ax/agent-claude-sdk-runner when neither override is set', () => {
+    const result = resolveRunnerBinary({});
+    expect(result).toMatch(/agent-claude-sdk-runner.*main\.js$/);
+  });","path":"packages/cli/src/__tests__/main-options.test.ts","commit_id":"d6817571cf23e9e6e190ffe225d6dc5cf4e85f33","original_commit_id":"c306cbc9c264552cd74fc9cc3c7117725c4181e5","user":{"login":"vpulim","id":100092,"node_id":"MDQ6VXNlcjEwMDA5Mg==","avatar_url":"https://avatars.githubusercontent.com/u/100092?v=4","gravatar_id":"","url":"https://api.github.com/users/vpulim","html_url":"https://github.com/vpulim","followers_url":"https://api.github.com/users/vpulim/followers","following_url":"https://api.github.com/users/vpulim/following{/other_user}","gists_url":"https://api.github.com/users/vpulim/gists{/gist_id}","starred_url":"https://api.github.com/users/vpulim/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/vpulim/subscriptions","organizations_url":"https://api.github.com/users/vpulim/orgs","repos_url":"https://api.github.com/users/vpulim/repos","events_url":"https://api.github.com/users/vpulim/events{/privacy}","received_events_url":"https://api.github.com/users/vpulim/received_events","type":"User","user_view_type":"public","site_admin":false},"body":"Fixed in d681757. Switched to `expect(result).toContain('agent-claude-sdk-runner')` + `expect(basename(result)).toBe('main.js')`.","created_at":"2026-04-29T14:44:04Z","updated_at":"2026-04-29T14:44:04Z","html_url":"https://github.com/project-ax/ax-next/pull/25#discussion_r3161884020","pull_request_url":"https://api.github.com/repos/project-ax/ax-next/pulls/25","_links":{"self":{"href":"https://api.github.com/repos/project-ax/ax-next/pulls/comments/3161884020"},"html":{"href":"https://github.com/project-ax/ax-next/pull/25#discussion_r3161884020"},"pull_request":{"href":"https://api.github.com/repos/project-ax/ax-next/pulls/25"}},"reactions":{"url":"https://api.github.com/repos/project-ax/ax-next/pulls/comments/3161884020/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"start_line":36,"original_start_line":35,"start_side":"RIGH